import asyncio
import json
import os
import urllib.request

MAX_VIDEOS = 100
VIDEOS_PER_PAGE = 20
MAX_PAGES = (MAX_VIDEOS + VIDEOS_PER_PAGE - 1) // VIDEOS_PER_PAGE

all_videos = []
collected = 0

async def run(page, context):
    global collected
    for page_num in range(MAX_PAGES):
        if collected >= MAX_VIDEOS:
            break

        await page.wait_for_timeout(2000)

        items = await page.evaluate("""() => {
            const results = [];
            const selectors = [
                'ytd-video-renderer',
                'ytd-grid-video-renderer',
                'ytd-compact-video-renderer',
                '[data-video-id]',
                '.video-card',
                '.video-item',
            ];
            let elements = [];
            for (const sel of selectors) {
                const found = document.querySelectorAll(sel);
                if (found.length > 0) {
                    elements = found;
                    break;
                }
            }
            if (elements.length === 0) {
                const anchors = document.querySelectorAll('a[href*="/watch"]');
                anchors.forEach(a => {
                    const titleEl = a.querySelector('img, [alt]') || a;
                    results.push({
                        title: titleEl.getAttribute('title') || titleEl.getAttribute('alt') || a.textContent.trim().slice(0, 100),
                        link: a.href,
                        thumbnail: a.querySelector('img') ? a.querySelector('img').src : ''
                    });
                });
            } else {
                elements.forEach(el => {
                    const anchor = el.querySelector('a[href*="/watch"]') || el.closest('a');
                    const titleEl = el.querySelector('#video-title, .title, [title]') || el;
                    const imgEl = el.querySelector('img');
                    results.push({
                        title: titleEl.getAttribute('title') || titleEl.textContent.trim().slice(0, 100),
                        link: anchor ? anchor.href : '',
                        thumbnail: imgEl ? imgEl.src : ''
                    });
                });
            }
            return results;
        }""")

        remaining = MAX_VIDEOS - collected
        items = items[:remaining]

        for item in items:
            if collected >= MAX_VIDEOS:
                break
            title = item.get('title', 'untitled').strip()
            if not title:
                title = f'video_{collected + 1}'
            safe_title = ''.join(c if c.isalnum() or c in ' ._-' else '_' for c in title)
            safe_title = safe_title[:80]

            thumbnail = item.get('thumbnail', '')
            if thumbnail and thumbnail.startswith('http'):
                ext = '.jpg'
                if '.png' in thumbnail:
                    ext = '.png'
                elif '.webp' in thumbnail:
                    ext = '.webp'
                img_filename = safe_title + ext
                try:
                    download_file(thumbnail, img_filename, subdir='thumbnails')
                except Exception as e:
                    pass

            all_videos.append({
                'index': collected + 1,
                'title': title,
                'link': item.get('link', ''),
                'thumbnail_saved': bool(thumbnail and thumbnail.startswith('http')),
            })
            collected += 1

        if collected < MAX_VIDEOS and page_num < MAX_PAGES - 1:
            next_selectors = [
                'a#pnnext',
                'button[aria-label="Next"]',
                'a[aria-label="Next page"]',
                '.next-page',
                'a.next',
                'button.next',
            ]
            clicked = False
            for sel in next_selectors:
                try:
                    el = page.locator(sel).first
                    if await el.is_visible(timeout=2000):
                        await el.click()
                        clicked = True
                        await page.wait_for_timeout(3000)
                        break
                except Exception:
                    continue
            if not clicked:
                try:
                    await page.evaluate('window.scrollBy(0, document.body.scrollHeight)')
                    await page.wait_for_timeout(3000)
                except Exception:
                    break

    save_json('video_crawl_results', {
        'total_videos': collected,
        'pages_crawled': page_num + 1 if 'page_num' in dir() else 1,
        'videos': all_videos,
    })

    result = {
        'total_videos': collected,
        'videos': all_videos,
        'output_dir': output_dir,
    }
    return result
